__d(function(g,r,i,a,m,e,d){m.exports="PRAGMA journal_mode = WAL;\nPRAGMA foreign_keys = ON;\n\n-- -----------------------------------------------------------------------------\n-- rrules\n-- Stores a parsed RRULE for a given event. One-to-one with vevents (0..1).\n-- BYDAY, BYSECOND, etc. are stored as comma-separated strings because SQLite\n-- has no array type; application layer is responsible for serialising /\n-- deserialising them.\n-- -----------------------------------------------------------------------------\nCREATE TABLE IF NOT EXISTS rrules (\n    id              INTEGER PRIMARY KEY,\n    vevent_uid      TEXT    NOT NULL REFERENCES vevents (uid) ON DELETE CASCADE,\n    freq            TEXT    NOT NULL\n                    CHECK (freq IN ('SECONDLY','MINUTELY','HOURLY','DAILY','WEEKLY','MONTHLY','YEARLY')),\n    until           TEXT,\n    count           INTEGER CHECK (count IS NULL OR count > 0),\n    interval        INTEGER NOT NULL DEFAULT 1 CHECK (interval >= 1),\n\n    -- BY* parts: stored as comma-separated values\n    -- e.g. byday = \"MO,+2FR,-1SU\"  (ordinal prefix allowed for byday)\n    bysecond        TEXT,   -- \"0,15,30,45\"\n    byminute        TEXT,   -- \"0,30\"\n    byhour          TEXT,   -- \"8,12,18\"\n    byday           TEXT,   -- \"MO,WE,FR\" or \"+1MO,-1FR\"\n    bymonthday      TEXT,   -- \"1,15,-1\"\n    byyearday       TEXT,   -- \"1,100,-1\"\n    byweekno        TEXT,   -- \"1,26,-1\"\n    bymonth         TEXT,   -- \"1,6,12\"\n    bysetpos        TEXT,   -- \"1,-1\"\n\n    wkst            TEXT    NOT NULL DEFAULT 'MO'\n                    CHECK (wkst IN ('SU','MO','TU','WE','TH','FR','SA')),\n\n    created_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),\n    updated_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),\n\n    CHECK (\n        -- at most one end-boundary constraint\n        NOT (until IS NOT NULL AND count IS NOT NULL)\n    )\n);\n\n-- -----------------------------------------------------------------------------\n-- vevents\n-- Core calendar event. dtend and duration are mutually exclusive.\n-- -----------------------------------------------------------------------------\nCREATE TABLE IF NOT EXISTS vevents (\n    uid             TEXT    PRIMARY KEY,\n    dtstamp         TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),           -- ISO 8601 date-time\n    dtstart         TEXT    NOT NULL,                       -- ISO 8601 date or date-time\n    dtend           TEXT    NOT NULL,                       -- mutually exclusive with duration\n    all_day         INTEGER NOT NULL DEFAULT 0  -- 1 = DATE-only (no time component)\n                    CHECK (all_day IN (0, 1)),\n\n    -- Recurrence (FK to rrules; nullable = no recurrence)\n    rrule_id        INTEGER REFERENCES rrules (id) ON DELETE SET NULL,\n\n    -- Exception / addition dates stored as newline-separated ISO 8601 strings.\n    -- Prefer a separate junction table for large sets (see notes below).\n    exdate          TEXT,                       -- excluded occurrence dates\n    rdate           TEXT,                       -- additional occurrence dates\n\n    -- For overrides of a recurring event, override master event's dtstart\n    recurrence_id   TEXT,                       -- ISO 8601 date-time of the master occurrence\n    \n    -- uid of the master event this override belongs to (self-referential via uid)\n    master_uid      TEXT    REFERENCES vevents (uid) ON DELETE CASCADE,\n    summary         TEXT    NOT NULL,\n    description     TEXT,\n    location        TEXT,\n    url             TEXT,\n    categories      TEXT,                       -- comma-separated\n    comment         TEXT,\n    status          TEXT    CHECK (status IN ('TENTATIVE','CONFIRMED','CANCELLED')),\n    class           TEXT    NOT NULL DEFAULT 'PUBLIC'\n                    CHECK (class IN ('PUBLIC','PRIVATE','CONFIDENTIAL')),\n    transp          TEXT    NOT NULL DEFAULT 'OPAQUE'\n                    CHECK (transp IN ('OPAQUE','TRANSPARENT')),\n    priority        INTEGER CHECK (priority IS NULL OR (priority >= 0 AND priority <= 9)),\n    sequence        INTEGER NOT NULL DEFAULT 0 CHECK (sequence >= 0),\n    created_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),\n    updated_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now'))\n);\n\n-- -----------------------------------------------------------------------------\n-- valarms\n-- Alarm components nested inside a VEVENT.\n-- -----------------------------------------------------------------------------\nCREATE TABLE IF NOT EXISTS valarms (\n    id              INTEGER PRIMARY KEY,\n    vevent_uid      TEXT    NOT NULL REFERENCES vevents (uid) ON DELETE CASCADE,\n\n    -- Required\n    action          TEXT    NOT NULL\n                    CHECK (action IN ('AUDIO','DISPLAY','EMAIL','PROCEDURE')),\n\n    -- Trigger: relative OR absolute (application enforces mutual exclusion)\n    trigger_type    TEXT    NOT NULL\n                    CHECK (trigger_type IN ('RELATIVE','ABSOLUTE')),\n\n    -- For RELATIVE triggers\n    trigger_duration    TEXT,                   -- iCal duration string, e.g. \"-PT15M\"\n    trigger_related     TEXT    CHECK (trigger_related IN ('START','END')),\n\n    -- For ABSOLUTE triggers\n    trigger_datetime    TEXT,                   -- ISO 8601 date-time\n\n    -- Repetition\n    repeat_count    INTEGER CHECK (repeat_count IS NULL OR repeat_count >= 0),\n    repeat_duration TEXT,                       -- iCal duration string between repeats\n\n    -- DISPLAY / EMAIL\n    description     TEXT,\n\n    -- EMAIL\n    summary         TEXT,\n\n    -- AUDIO\n    attach_uri      TEXT,\n\n    created_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),\n    updated_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),\n\n    CHECK (\n        CASE trigger_type\n            WHEN 'RELATIVE' THEN trigger_duration IS NOT NULL\n            WHEN 'ABSOLUTE' THEN trigger_datetime IS NOT NULL\n        END\n    ),\n    CHECK (\n        -- EMAIL action requires description and summary\n        action != 'EMAIL' OR (description IS NOT NULL AND summary IS NOT NULL)\n    ),\n    CHECK (\n        -- DISPLAY action requires description\n        action != 'DISPLAY' OR description IS NOT NULL\n    ),\n    CHECK (\n        -- repeat_count and repeat_duration must both be set or both absent\n        (repeat_count IS NULL) = (repeat_duration IS NULL)\n    )\n);\n\n-- -----------------------------------------------------------------------------\n-- Indexes\n-- -----------------------------------------------------------------------------\n-- CREATE INDEX IF NOT EXISTS idx_vevents_uid           ON vevents (uid); -- Redundant with PRIMARY KEY\nCREATE INDEX IF NOT EXISTS idx_vevents_dtstart       ON vevents (dtstart);\nCREATE INDEX IF NOT EXISTS idx_vevents_dtend         ON vevents (dtend);\nCREATE INDEX IF NOT EXISTS idx_vevents_master_uid    ON vevents (master_uid);\nCREATE INDEX IF NOT EXISTS idx_vevents_rrule_id      ON vevents (rrule_id);\nCREATE INDEX IF NOT EXISTS idx_valarms_vevent_uid    ON valarms (vevent_uid);\nCREATE INDEX IF NOT EXISTS idx_rrules_vevent_uid    ON rrules (vevent_uid);\n\n-- -----------------------------------------------------------------------------\n-- updated_at triggers\n-- -----------------------------------------------------------------------------\nCREATE TRIGGER IF NOT EXISTS trg_vevents_updated_at\n    AFTER UPDATE ON vevents\n    FOR EACH ROW\nBEGIN\n    UPDATE vevents SET updated_at = strftime('%Y-%m-%dT%H:%M:%fZ','now')\n    WHERE uid = OLD.uid;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_rrules_updated_at\n    AFTER UPDATE ON rrules\n    FOR EACH ROW\nBEGIN\n    UPDATE rrules SET updated_at = strftime('%Y-%m-%dT%H:%M:%fZ','now')\n    WHERE id = OLD.id;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_valarms_updated_at\n    AFTER UPDATE ON valarms\n    FOR EACH ROW\nBEGIN\n    UPDATE valarms SET updated_at = strftime('%Y-%m-%dT%H:%M:%fZ','now')\n    WHERE id = OLD.id;\nEND;"},1533,[]);
